use core::sync::atomic::{AtomicUsize, Ordering};
use std::sync::LazyLock;

struct SharedCounter {
    value: AtomicUsize,
}

impl SharedCounter {
    fn new() -> Self {
        SharedCounter { value: AtomicUsize::new(0) }
    }

    fn increment(&self) -> usize {
        self.value.fetch_add(1, Ordering::SeqCst) + 1
    }
}

struct Worker {
    id: usize,
    counter: &'static SharedCounter,
}

impl Worker {
    fn new(id: usize, counter: &'static SharedCounter) -> Self {
        Worker { id, counter }
    }

    fn run(&self) -> usize {
        let result = self.counter.increment();
        println!("Worker {} finished with value {}", self.id, result);
        result
    }
}

fn main() {
    static COUNTER: LazyLock<SharedCounter> = LazyLock::new(|| SharedCounter::new());

    let workers = vec![ 
        Worker::new(1, &*COUNTER), 
        Worker::new(2, &*COUNTER), 
        Worker::new(3, &*COUNTER) 
    ];

    let mut handles = Vec::new();
    for worker in workers {
        handles.push(worker);
    }

    let final_sum: usize = handles.into_iter().map(|w| w.run()).sum();
    println!("Final total count incremented: {}", final_sum);
}

use core::mem::{self, MaybeUninit};
struct ColumnarStore {
    data: Vec<u32>,
}

impl ColumnarStore {
    fn new() -> Self {
        ColumnarStore {
            data: Vec::new(),
        }
    }

    fn process_rle(&mut self, input_stream: &[u32]) {
        if input_stream.is_empty() {
            return;
        }

        let mut run_values = Vec::new();
        let mut run_lengths = Vec::new();

        let mut current_value = *input_stream.get(0).unwrap();
        let mut count = 1;

        for &next_value in input_stream.iter().skip(1) {
            if next_value == current_value {
                count += 1;
            } else {
                run_values.push(current_value);
                run_lengths.push(count as u32);
                current_value = next_value;
                count = 1;
            }
        }
        run_values.push(current_value);
        run_lengths.push(count as u32);

        self.data.extend(run_values);
        self.data.extend(run_lengths.iter().cloned());
    }
}

fn main() {
    let raw_data = vec![5, 5, 5, 10, 10, 20, 20];
    let mut store = ColumnarStore::new();
    store.process_rle(&raw_data);

    println!("Stored values: {:?}", &store.data[0..raw_data.len() as usize / 3]);
    println!("Stored counts: {:?}", &store.data[raw_data.len() as usize / 3..2 * raw_data.len() as usize / 3]);
}
